/// Configuration for the dispatcher.
#[derive(Debug, Clone)]
pub struct DispatchConfig {
    /// Default dispatch strategy.
    pub default_strategy: DispatchStrategy,

    /// Timeout for each dispatch attempt.
    pub timeout: Time,

    /// Maximum retries per endpoint.
    pub max_retries: u32,

    /// Delay between retries.
    pub retry_delay: Time,

    /// Whether to fail fast on first error.
    pub fail_fast: bool,

    /// Maximum concurrent dispatches.
    pub max_concurrent: u32,
}

impl Default for DispatchConfig {
    fn default() -> Self {
        Self {
            default_strategy: DispatchStrategy::Unicast,
            timeout: Time::from_secs(5),
            max_retries: 3,
            retry_delay: Time::from_millis(100),
            fail_fast: false,
            max_concurrent: 100,
        }
    }
}

/// The symbol dispatcher sends symbols to resolved endpoints.
#[derive(Debug)]
pub struct SymbolDispatcher {
    /// The router.
    router: Arc<SymbolRouter>,

    /// Configuration.
    config: DispatchConfig,

    /// Active dispatch count.
    active_dispatches: AtomicU32,

    /// Total symbols dispatched.
    total_dispatched: AtomicU64,

    /// Total failures.
    total_failures: AtomicU64,
}

impl SymbolDispatcher {
    /// Creates a new dispatcher.
    pub fn new(router: Arc<SymbolRouter>, config: DispatchConfig) -> Self {
        Self {
            router,
            config,
            active_dispatches: AtomicU32::new(0),
            total_dispatched: AtomicU64::new(0),
            total_failures: AtomicU64::new(0),
        }
    }

    /// Dispatches a symbol using the default strategy.
    pub async fn dispatch(&self, symbol: Symbol) -> Result<DispatchResult, DispatchError> {
        self.dispatch_with_strategy(symbol, self.config.default_strategy).await
    }

    /// Dispatches a symbol with a specific strategy.
    pub async fn dispatch_with_strategy(
        &self,
        symbol: Symbol,
        strategy: DispatchStrategy,
    ) -> Result<DispatchResult, DispatchError> {
        // Check concurrent dispatch limit
        let active = self.active_dispatches.fetch_add(1, Ordering::SeqCst);
        if active >= self.config.max_concurrent {
            self.active_dispatches.fetch_sub(1, Ordering::SeqCst);
            return Err(DispatchError::Overloaded);
        }

        let start = Time::ZERO; // Would use actual time in impl
        let result = match strategy {
            DispatchStrategy::Unicast => {
                self.dispatch_unicast(&symbol).await
            }
            DispatchStrategy::Multicast { count } => {
                self.dispatch_multicast(&symbol, count).await
            }
            DispatchStrategy::Broadcast => {
                self.dispatch_broadcast(&symbol).await
            }
            DispatchStrategy::QuorumCast { required } => {
                self.dispatch_quorum(&symbol, required).await
            }
        };

        self.active_dispatches.fetch_sub(1, Ordering::SeqCst);

        match &result {
            Ok(r) => {
                self.total_dispatched.fetch_add(r.successes as u64, Ordering::Relaxed);
                self.total_failures.fetch_add(r.failures as u64, Ordering::Relaxed);
            }
            Err(_) => {
                self.total_failures.fetch_add(1, Ordering::Relaxed);
            }
        }

        result
    }

    /// Dispatches to a single endpoint.
    async fn dispatch_unicast(&self, symbol: &Symbol) -> Result<DispatchResult, DispatchError> {
        let route = self.router.route(symbol)?;

        // Attempt to send (placeholder - actual transport would go here)
        route.endpoint.acquire_connection();

        // Simulate sending
        let success = true; // Would be actual send result

        route.endpoint.release_connection();

        if success {
            route.endpoint.record_success(Time::ZERO);
            Ok(DispatchResult {
                successes: 1,
                failures: 0,
                sent_to: vec![route.endpoint.id],
                failed_endpoints: vec![],
                duration: Time::ZERO,
            })
        } else {
            route.endpoint.record_failure(Time::ZERO);
            Err(DispatchError::SendFailed {
                endpoint: route.endpoint.id,
                reason: "Send failed".into(),
            })
        }
    }

    /// Dispatches to multiple endpoints.
    async fn dispatch_multicast(
        &self,
        symbol: &Symbol,
        count: usize,
    ) -> Result<DispatchResult, DispatchError> {
        let routes = self.router.route_multicast(symbol, count)?;

        let mut successes = 0;
        let mut failures = 0;
        let mut sent_to = Vec::new();
        let mut failed = Vec::new();

        for route in routes {
            route.endpoint.acquire_connection();

            // Simulate sending
            let success = true; // Would be actual send result

            route.endpoint.release_connection();

            if success {
                route.endpoint.record_success(Time::ZERO);
                successes += 1;
                sent_to.push(route.endpoint.id);
            } else {
                route.endpoint.record_failure(Time::ZERO);
                failures += 1;
                failed.push((
                    route.endpoint.id,
                    DispatchError::SendFailed {
                        endpoint: route.endpoint.id,
                        reason: "Send failed".into(),
                    },
                ));
            }

            if self.config.fail_fast && failures > 0 {
                break;
            }
        }

        Ok(DispatchResult {
            successes,
            failures,
            sent_to,
            failed_endpoints: failed,
            duration: Time::ZERO,
        })
    }

    /// Dispatches to all endpoints.
    async fn dispatch_broadcast(&self, symbol: &Symbol) -> Result<DispatchResult, DispatchError> {
        let endpoints = self.router.table().healthy_endpoints();

        if endpoints.is_empty() {
            return Err(DispatchError::NoEndpoints);
        }

        let mut successes = 0;
        let mut failures = 0;
        let mut sent_to = Vec::new();
        let mut failed = Vec::new();

        for endpoint in endpoints {
            endpoint.acquire_connection();

            // Simulate sending
            let success = true;

            endpoint.release_connection();

            if success {
                endpoint.record_success(Time::ZERO);
                successes += 1;
                sent_to.push(endpoint.id);
            } else {
                endpoint.record_failure(Time::ZERO);
                failures += 1;
                failed.push((
                    endpoint.id,
                    DispatchError::SendFailed {
                        endpoint: endpoint.id,
                        reason: "Send failed".into(),
                    },
                ));
            }
        }

        Ok(DispatchResult {
            successes,
            failures,
            sent_to,
            failed_endpoints: failed,
            duration: Time::ZERO,
        })
    }

    /// Dispatches until quorum is reached.
    async fn dispatch_quorum(
        &self,
        symbol: &Symbol,
        required: usize,
    ) -> Result<DispatchResult, DispatchError> {
        let endpoints = self.router.table().healthy_endpoints();

        if endpoints.len() < required {
            return Err(DispatchError::InsufficientEndpoints {
                available: endpoints.len(),
                required,
            });
        }

        let mut successes = 0;
        let mut failures = 0;
        let mut sent_to = Vec::new();
        let mut failed = Vec::new();

        for endpoint in endpoints {
            if successes >= required {
                break;
            }

            endpoint.acquire_connection();

            // Simulate sending
            let success = true;

            endpoint.release_connection();

            if success {
                endpoint.record_success(Time::ZERO);
                successes += 1;
                sent_to.push(endpoint.id);
            } else {
                endpoint.record_failure(Time::ZERO);
                failures += 1;
                failed.push((
                    endpoint.id,
                    DispatchError::SendFailed {
                        endpoint: endpoint.id,
                        reason: "Send failed".into(),
                    },
                ));
            }
        }

        if successes < required {
            return Err(DispatchError::QuorumNotReached {
                achieved: successes,
                required,
            });
        }

        Ok(DispatchResult {
            successes,
            failures,
            sent_to,
            failed_endpoints: failed,
            duration: Time::ZERO,
        })
    }

    /// Returns dispatcher statistics.
    #[must_use]
    pub fn stats(&self) -> DispatcherStats {
        DispatcherStats {
            active_dispatches: self.active_dispatches.load(Ordering::Relaxed),
            total_dispatched: self.total_dispatched.load(Ordering::Relaxed),
            total_failures: self.total_failures.load(Ordering::Relaxed),
        }
    }
}

/// Dispatcher statistics.
#[derive(Debug, Clone)]
pub struct DispatcherStats {
    /// Currently active dispatches.
    pub active_dispatches: u32,

    /// Total symbols dispatched.
    pub total_dispatched: u64,

    /// Total failures.
    pub total_failures: u64,
}

// ============================================================================
// Error Types
// ============================================================================

/// Errors from routing.
#[derive(Debug, Clone)]
pub enum RoutingError {
    /// No route found for the symbol.
    NoRoute {
        object_id: ObjectId,
        reason: String,
    },

    /// No healthy endpoints available.
    NoHealthyEndpoints {
        object_id: ObjectId,
    },

    /// Route table is empty.
    EmptyTable,
}

impl std::fmt::Display for RoutingError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::NoRoute { object_id, reason } => {
                write!(f, "no route for object {:?}: {}", object_id, reason)
            }
            Self::NoHealthyEndpoints { object_id } => {
                write!(f, "no healthy endpoints for object {:?}", object_id)
            }
            Self::EmptyTable => write!(f, "routing table is empty"),
        }
    }
}

impl std::error::Error for RoutingError {}

impl From<RoutingError> for Error {
    fn from(e: RoutingError) -> Self {
        Error::new(ErrorKind::RoutingFailed).with_context(e.to_string())
    }
}

/// Errors from dispatch.
#[derive(Debug, Clone)]
pub enum DispatchError {
    /// Routing failed.
    RoutingFailed(RoutingError),

    /// Send failed.
    SendFailed {
        endpoint: EndpointId,
        reason: String,
    },

    /// Dispatcher is overloaded.
    Overloaded,

    /// No endpoints available.
    NoEndpoints,

    /// Insufficient endpoints for quorum.
    InsufficientEndpoints {
        available: usize,
        required: usize,
    },

    /// Quorum not reached.
    QuorumNotReached {
        achieved: usize,
        required: usize,
    },

    /// Timeout.
    Timeout,
}

impl std::fmt::Display for DispatchError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::RoutingFailed(e) => write!(f, "routing failed: {}", e),
            Self::SendFailed { endpoint, reason } => {
                write!(f, "send to {} failed: {}", endpoint, reason)
            }
            Self::Overloaded => write!(f, "dispatcher overloaded"),
            Self::NoEndpoints => write!(f, "no endpoints available"),
            Self::InsufficientEndpoints { available, required } => {
                write!(f, "insufficient endpoints: {} available, {} required", available, required)
            }
            Self::QuorumNotReached { achieved, required } => {
                write!(f, "quorum not reached: {} of {} required", achieved, required)
            }
            Self::Timeout => write!(f, "dispatch timeout"),
        }
    }
}

impl std::error::Error for DispatchError {}

impl From<RoutingError> for DispatchError {
    fn from(e: RoutingError) -> Self {
        Self::RoutingFailed(e)
    }
}

impl From<DispatchError> for Error {
    fn from(e: DispatchError) -> Self {
        match e {
            DispatchError::RoutingFailed(_) => {
                Error::new(ErrorKind::RoutingFailed).with_context(e.to_string())
            }
            DispatchError::QuorumNotReached { .. } => {
                Error::new(ErrorKind::QuorumNotReached).with_context(e.to_string())
            }
            _ => {
                Error::new(ErrorKind::DispatchFailed).with_context(e.to_string())
            }
        }
    }
}
