## Logging Strategy

```rust
use crate::observability::{LogEntry, LogLevel};

impl SymbolRouter {
    fn log_route(&self, symbol: &Symbol, result: &RouteResult) -> LogEntry {
        LogEntry::debug("Symbol routed")
            .with_field("object_id", &format!("{:?}", symbol.object_id()))
            .with_field("endpoint", &format!("{}", result.endpoint.id))
            .with_field("matched_key", &format!("{:?}", result.matched_key))
            .with_field("is_fallback", &result.is_fallback.to_string())
    }

    fn log_route_failure(&self, symbol: &Symbol, error: &RoutingError) -> LogEntry {
        LogEntry::warn("Symbol routing failed")
            .with_field("object_id", &format!("{:?}", symbol.object_id()))
            .with_field("error", &error.to_string())
    }
}

impl SymbolDispatcher {
    fn log_dispatch(&self, symbol: &Symbol, strategy: DispatchStrategy) -> LogEntry {
        LogEntry::debug("Dispatching symbol")
            .with_field("object_id", &format!("{:?}", symbol.object_id()))
            .with_field("strategy", &format!("{:?}", strategy))
    }

    fn log_dispatch_result(&self, result: &DispatchResult) -> LogEntry {
        let level = if result.failures > 0 {
            LogLevel::Warn
        } else {
            LogLevel::Debug
        };

        LogEntry::new(level, "Dispatch completed")
            .with_field("successes", &result.successes.to_string())
            .with_field("failures", &result.failures.to_string())
            .with_field("endpoints", &format!("{}", result.sent_to.len()))
    }
}

impl Endpoint {
    fn log_state_change(&self, old: EndpointState, new: EndpointState) -> LogEntry {
        LogEntry::info("Endpoint state changed")
            .with_field("endpoint_id", &format!("{}", self.id))
            .with_field("address", &self.address)
            .with_field("from", &format!("{:?}", old))
            .with_field("to", &format!("{:?}", new))
    }
}
```

